import java.io.File;
import java.util.Scanner;

public class SecurePathTraversal {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter a file name:");
        String fileName = scanner.nextLine();

        if (isFilenameValid(fileName)) {
            File file = new File("/path/to/directory/", fileName);

            if (file.exists()) {
                System.out.println("File exists!");
                // Do something with the file
            } else {
                System.out.println("File not found.");
            }
        } else {
            System.out.println("Invalid file name.");
        }
    }

    private static boolean isFilenameValid(String fileName) {
        // Implement validation logic here to ensure filename does not contain path traversal characters
        return !fileName.contains(".."); // Simple check for ".." which signifies directory traversal
    }
}

